import{_ as e,o as s,c as i,ag as t}from"./chunks/framework.DCX4NPYl.js";const m=JSON.parse('{"title":"Cloze Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Cloze-Cards.md","filePath":"Cloze-Cards.md","lastUpdated":1772690052000}'),n={name:"Cloze-Cards.md"};function r(l,a,o,c,d,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="cloze-cards" tabindex="-1">Cloze Cards <a class="header-anchor" href="#cloze-cards" aria-label="Permalink to &quot;Cloze Cards&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Cloze cards hide words inside a sentence so you recall missing parts in context.</p><h2 id="basic-cloze-format" tabindex="-1">Basic cloze format <a class="header-anchor" href="#basic-cloze-format" aria-label="Permalink to &quot;Basic cloze format&quot;">​</a></h2><p>Use <code>CQ</code> with markers like <code>&amp;#123;&amp;#123;c1::...&amp;#125;&amp;#125;</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | French Geography |</span></span>
<span class="line"><span>CQ | The capital of France is &amp;#123;&amp;#123;c1::Paris&amp;#125;&amp;#125; |</span></span>
<span class="line"><span>I | Located on the River Seine |</span></span>
<span class="line"><span>G | Geography |</span></span></code></pre></div><h2 id="numbering-rules" tabindex="-1">Numbering rules <a class="header-anchor" href="#numbering-rules" aria-label="Permalink to &quot;Numbering rules&quot;">​</a></h2><ul><li>Different numbers (<code>c1</code>, <code>c2</code>) create separate cards.</li><li>Same number hides multiple parts on the same card.</li></ul><p>Example with two cards:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CQ | &amp;#123;&amp;#123;c1::Paris&amp;#125;&amp;#125; is the capital of &amp;#123;&amp;#123;c2::France&amp;#125;&amp;#125; |</span></span></code></pre></div><p>Example with one card hiding two words:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CQ | The &amp;#123;&amp;#123;c1::heart&amp;#125;&amp;#125; pumps &amp;#123;&amp;#123;c1::blood&amp;#125;&amp;#125; through the body |</span></span></code></pre></div><h2 id="create-with-the-modal" tabindex="-1">Create with the modal <a class="header-anchor" href="#create-with-the-modal" aria-label="Permalink to &quot;Create with the modal&quot;">​</a></h2><ol><li>Right-click in a note → <strong>Add flashcard → Cloze Card</strong>.</li><li>Enter text.</li><li>Mark text as new cloze or same-number cloze.</li><li>Save.</li></ol><h2 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h2><p>Cloze cards use the same manual grading flow as other cards. See <a href="./Grading">Grading</a>.</p><h2 id="edge-cases-and-limits" tabindex="-1">Edge cases and limits <a class="header-anchor" href="#edge-cases-and-limits" aria-label="Permalink to &quot;Edge cases and limits&quot;">​</a></h2><ul><li>Invalid cloze syntax can stop a card from rendering correctly.</li><li>Overlapping or inconsistent numbering can create unexpected card counts.</li><li>Very large numbers of deletions in one sentence can hurt readability and recall quality.</li></ul>`,19)])])}const u=e(n,[["render",r]]);export{m as __pageData,u as default};
